var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"감사합니다. 기사님께는 정말 어떻게 보답해야 할지 모르겠네요.","JPN":"ありがとうございます。騎士様には本当にどう恩返しすればいいか……","ENG":"Thank you. I truly don't know how to repay you.","TWN":"謝謝你。我真的不知道該如何報答你，騎士小姐。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"은혜를 느끼고 있는 건 제 쪽이니 너무 염려치 마시죠.","JPN":"お気遣いなく。恩返しするべきなのは私のほうです。","ENG":"If anyone owes gratitude, it's me. So don't worry.","TWN":"感受到恩惠的是我，所以請不要太擔心。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"덕분에 조금이지만 제가 나아가야 할 길이 보였습니다.","JPN":"おかげさまで、少しですが自分の進むべき道が見えてきました。","ENG":"Thanks to you, I've finally caught a glimpse of the path I should take.","TWN":"多虧了你，我稍微看到了我要前進的道路。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"그렇게 느끼신다니 다행이네요.","JPN":"それならよかったです。","ENG":"I'm glad to hear that.","TWN":"你有這樣的感覺就好。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"기사님께도 여러 사정이 있으실 테니, 자세한 건 묻지 않겠습니다.","JPN":"騎士様にも色々な事情があるはずですし、詳しいことはお聞きしません。","ENG":"I'm sure you have your own circumstances, so I won't ask for details.","TWN":"騎士也有各種情況，所以我就不詳細詢問了。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"얘들아. 기사님한테 잘 가시라고 인사해야지?","JPN":"みんな、騎士様にご挨拶しなさい。","ENG":"Kids, come say goodbye properly.","TWN":"孩子們。要跟騎士姊姊說再見喔？"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"다음에 오실 땐 다른 분들도 데려와 주세요!","JPN":"次は他の人も連れてきて！","ENG":"Next time, can you bring the others too?","TWN":"下次來的時候請帶其他人一起來喔！"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"버고 소드도요! 저 그거 만져보고 싶어요!","JPN":"ヴァルゴソードも！　あれ触ってみたい！","ENG":"And the Virgo Sword! I really want to see it!","TWN":"布林加夫之劍也可以嗎！我想摸摸那個！"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"욘석들! 인사를 해야지 불편을 끼치면 어떡해?","JPN":"こら！　迷惑をかけてどうする！","ENG":"Children! That's not how you say goodbye. Don't be rude.","TWN":"你們這些傢伙！怎麼能不打招呼就給人添麻煩呢？"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"저기, 기사님…….","JPN":"あの、騎士様……","ENG":"Um, Miss Knight...?","TWN":"那個，騎士姊姊……"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"감사를 표하지, 엠마. 너에겐 특히 많은 도움을 받았다.","JPN":"礼を言わせてくれ、エマ。君には特にたくさん助けてもらった。","ENG":"Thank you, Emma. You've helped me more than you know.","TWN":"感謝你，艾瑪。特別是你幫了我很多忙。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"아뇨, 아직 사인 못 받아서…….","JPN":"いえ、まだサインもらってないなと思って……","ENG":"No, I just haven't gotten your autograph yet...","TWN":"那個，還沒收到簽名……"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"미안하군. 지금의 난 너희들 앞에 당당히 서 있을만한 사람이 아니야.","JPN":"すまない。今の私は君たちの前に堂々と立っていられるような人間ではないんだ。","ENG":"I'm sorry. Right now, I'm not someone who deserves to stand proudly before you.","TWN":"抱歉。我現在還不是能堂堂正正站在你們面前的人。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"괜찮다면, 사인은 <color=#ffd34c>다음</color>에 해줘도 괜찮겠나?","JPN":"よかったら、サインは<color=#ffd34c>今度</color>にしてもらってもいいだろうか？","ENG":"Would it be all right if I gave you that autograph <color=#ffd34c>next time</color>?","TWN":"如果可以的話，簽名可以<color=#ffd34c>下次</color>再給嗎？"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"다음이요?","JPN":"今度？","ENG":"Next time?","TWN":"下次嗎？"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"……아! 네, 물론이죠!!","JPN":"……あ、はい！　もちろんです！","ENG":"...Oh! Yes, of course!!","TWN":"……啊！當然了！！"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"꼭 다시 만나요, 기사님!","JPN":"絶対また会いましょう、騎士様！","ENG":"Let's definitely meet again, Miss Knight!","TWN":"一定要再見喔，騎士姊姊！"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Sure.","TWN":"好的。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"또 보자, 엠마.","JPN":"また会おう、エマ。","ENG":"See you again, Emma.","TWN":"再見，艾瑪。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"이봐, 도착했어.","JPN":"おい、着いたぞ。","ENG":"Hey, we're here.","TWN":"喂，到了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"사전에도 말했지만, 우리 같은 용병 나부랭이들이 이 이상 동행하는 건 무리야.","JPN":"話したとおり、俺らのような傭兵ごときに、これ以上同行するのは無理だ。","ENG":"Like I said before, this is as far as we go. We're just mercs, not an escort service.","TWN":"雖然之前也說過，但像我們這樣的傭兵再繼續同行是不可能的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"통제구역을 통과할 때 쓴 위조 통행증 값. 그 외 이동료랑 인건비는…….","JPN":"統制エリアを通る時に使った偽造通行証の料金、その他の交通代と人件費は……","ENG":"The forged pass we used to get past the restricted zone, travel costs, and labor fees...","TWN":"通過控制區時使用的偽造通行證費用。其他的交通費和人工費是……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"돈이라면 보냈다. 확인해보도록.","JPN":"金なら送った。確認してくれ。","ENG":"Payment's been sent. You can check it.","TWN":"錢已經匯過去了。請確認一下。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"확인. 돈 거래도 끝났으니 서로 볼 장은 다 본 것 같네.","JPN":"確認した。金銭の取引も終わったことだし、もうお互い用はないな。","ENG":"Got it. Payment confirmed. I guess we're done here.","TWN":"確認。錢也已經收到了，看來我們之間的事情都解決了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"그런데 이 근방에 마을이 있는 건 확실한 거야?","JPN":"しかし、この辺に本当に村があるのか？","ENG":"But are you sure there's a village out here?","TWN":"但是，這附近真的有村莊嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"이제 와서 하는 말이지만 이 주변은 침식 지대라고.","JPN":"今更だが、この辺は侵食地帯だ。","ENG":"Hate to say this now, but this area's considered a Corrupted Area.","TWN":"現在說來，這周圍是侵蝕地帶。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"나중에 와서 위치를 착각했으니 환불해달라고 해도 곤란하다?","JPN":"後で場所を間違えたとか言って返金を要求してくるなよ？","ENG":"If you show up later claiming we got the place wrong and ask for a refund, don't bother.","TWN":"以後再來要求退款，說是搞錯了位置，這樣會很麻煩喔？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"착각이 아니니 안심해라. 조금 걸어야 하지만 외진 곳에 마을이 하나 있다.","JPN":"勘違いではないから安心しろ。少し歩く必要はあるが、郊外に村がある。","ENG":"Don't worry. It's not a mistake. It's a bit of a walk, but there's a village tucked away nearby.","TWN":"不是錯覺，放心吧。雖然要走一段路，但有一個偏僻的村莊。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"그래? 뭐, 비싼 돈 주고 왔으니 거짓말은 아니겠지.","JPN":"そうか？　ま、高い金払って来たんだし、嘘じゃないだろう。","ENG":"Yeah? Well, for the price you paid, I'll take your word for it.","TWN":"是嗎？嗯，花了那麼多錢來這裡，應該不會是騙人的吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그래. 확실하다.","JPN":"ああ、確かだ。","ENG":"I'm sure of it.","TWN":"好了。確定了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"거긴, 내 고향이거든.","JPN":"そこは私の故郷だから。","ENG":"That place is my hometown.","TWN":"那裡是我的故鄉。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"낯익은 풍경이 시야에 들어오자 잊고 있던 꽃내음이 코끝을 스친다.","JPN":"見慣れた景色が視野に入ると、忘れていた花の香が鼻をくすぐる。","ENG":"As familiar scenery came into view, a forgotten scent of flowers brushed past my nose.","TWN":"熟悉的風景映入眼簾，久違的花香撲鼻而來。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"멀리 아른거리는 작은 마을의 풍경이 솟아오른 나무 그림자에 가려져 흐릿하게 보일 때면.","JPN":"遠くにちらちらと見えていた小さな村の風景が、そびえ立つ木々の影に隠れておぼろげになると。","ENG":"When the shadow of a towering tree blurred the view of a tiny village shimmering in the distance...","TWN":"遠處隱約可見的小村莊景色被高聳的樹影遮擋，顯得模糊不清。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"그곳에서 외롭게 웅크린 채, 갈 길을 잃었던 어린 내 모습이 겹쳐졌다.","JPN":"行き場を失って寂しく体を丸めていた、幼い自分の姿が重なる。","ENG":"I saw the image of my younger self curled up, lost, and alone.","TWN":"在那裡孤獨地蜷縮著，彷彿看到了迷失方向的年幼的自己。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"본디 돌아갈 곳 하나 없이 유랑하는 이에게 고향이란 존재하지 않는다.","JPN":"帰る場所もなく流浪する者にとって、故郷など存在しないに等しい。","ENG":"A wanderer with no place to return to has no concept of home.","TWN":"對於本無歸處的流浪者而言，故鄉並不存在。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"그럼에도 <color=#ffd34c>우리</color>가 이곳을 마음의 안식처로 삼은 이유는.","JPN":"それでも<color=#ffd34c>私たち</color>がこの村を心の拠り所にしていた理由は。","ENG":"But <color=#ffd34c>we</color> called this place our sanctuary...","TWN":"儘管如此，我們還是將這裡視為心靈的安息之所的原因是。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"분명, 모든 만남이 이곳에서 시작되었기 때문이다.","JPN":"きっと、すべての出会いがここから始まったからだろう。","ENG":"Because all our beginnings started here.","TWN":"因為所有的相遇都是從這裡開始的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"마을에서 도둑질이 일어났다는 겁니까?","JPN":"村に泥棒が？","ENG":"There's been a theft in the village?","TWN":"難道村子裡發生了盜竊事件嗎？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"예. 외지에서 온 남매가 밭의 옥수수를 가져간 모양입니다.","JPN":"はい。外から来た兄妹が、畑のトウモロコシを盗んだようです。","ENG":"Yes. A brother and sister from outside apparently took corn from the fields.","TWN":"是的，看來是外地來的兄妹拿走了田裡的玉米。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"요즘 세상이 워낙 흉흉한 탓에 별거 아닌 일임에도 마을 사람들이 화가 난 모양이더군요.","JPN":"最近は世の中があまりにも物騒なせいか、たいしたことでもないのに村の連中が腹を立てとるようでして。","ENG":"Things have been tense lately, so even something small like this has the villagers riled up.","TWN":"最近因為世道太過險惡，即使是小事也讓村民們感到憤怒。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그건 이상하군요. 마을 주변은 침식지대라 아이들이 올만한 환경이 아닐 텐데요.","JPN":"それはおかしい。村の周辺は侵食地帯で、子どもが入ってこられるような場所ではないはずです。","ENG":"That's odd. This area's too close to the Corrupted Area for children to wander in.","TWN":"那真是奇怪。村莊周圍是侵蝕地帶，不是孩子們會來的環境啊。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"짐승의 소행을 마을 사람들이 착각한 게 아닐까 싶습니다.","JPN":"獣の素行を村の人が勘違いしたのではないかと。","ENG":"Are you sure it wasn't a wild animal?","TWN":"我覺得村民們可能誤以為是野獸所為。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"저도 처음에는 그렇게 생각했습니다만, 이미 오빠 쪽에게 잘못을 시인받은 뒤입니다.","JPN":"私も最初はそう思いましたが、すでに兄のほうが犯行を認めています。","ENG":"That's what I thought at first, but the boy admitted it himself.","TWN":"我一開始也是這麼想的，但已經讓哥哥那邊承認了錯誤。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"동생 쪽은 사람들을 피해 어딘가로 도망쳤지만… 아무래도 이 근방은 위험하니까요.","JPN":"妹のほうは人目を避けてどこかに逃げましたが……この辺は危ないですしね。","ENG":"The girl ran off, but... this area isn't exactly safe.","TWN":"妹妹那邊雖然躲開了人群逃到了某個地方……但這裡附近似乎很危險。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"시간이 남으실 때 교수님께서도 아이를 찾아 주시면 감사하겠습니다.","JPN":"お手すきの際に、教授も子どもを探してくださいませんか。","ENG":"If you have time, Professor, I'd be grateful if you helped find her.","TWN":"如果你有時間，也請教授幫忙找一下孩子，謝謝。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……솔직히 당장은 믿기 어렵지만.","JPN":"……正直、まだ信じがたいですが。","ENG":"...Hard to believe, honestly.","TWN":"……坦白說，現在很難相信。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"일단 알겠습니다, 촌장님.","JPN":"とりあえずわかりました、村長。","ENG":"But understood, Chief.","TWN":"明白，村長。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그 말을 듣고도 설마 싶었는데.","JPN":"……と聞いてもまさかと思っていたのだが。","ENG":"Even after hearing it, I still had my doubts.","TWN":"聽到那句話後，我還是覺得不可能。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"정말 있었군. 이런 곳에 옥수수 서리꾼이.","JPN":"本当にいたとはな、こんなところにトウモロコシ泥棒が。","ENG":"But here she is. A corn thief, in a place like this.","TWN":"真的有啊。在這種地方竟然有偷玉米的人。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"히, 히끅!","JPN":"ひ、ひくっ！","ENG":"E-eeek!","TWN":"欸？咿呀！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"자네에게 죄를 묻기 이전, 먼저 두 가지를 말해야겠군.","JPN":"君に罪を問う前に、言うことが2つある。","ENG":"Before I address the crime, let me say two things.","TWN":"在追究你的罪責之前，我得先說兩件事。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"우선 거긴 의자가 아니니 일어나도록.","JPN":"まず、そこは椅子ではないから立ちなさい。","ENG":"First, that's not a chair. Please stand up.","TWN":"首先，那不是椅子，快起來吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그리고, 여긴 어떻게 온 거지?","JPN":"そして、ここにはどうやって来た？","ENG":"And second, what are you doing here?","TWN":"而且，你是怎麼到這裡的？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"앉아있기 좋은 장소가 있다고 어떤 사람이 알려줬어요.","JPN":"座るのにいい場所があるって、ある人が教えてくれたの。","ENG":"Someone told me this was a good spot to sit.","TWN":"有人告訴我有個適合坐下來的地方。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"그래서…….","JPN":"それで……","ENG":"So I...","TWN":"所以……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"이곳에서 해가 지기를 기다렸겠군.","JPN":"ここで日が暮れるのを待っていたのか。","ENG":"You were waiting for sundown, weren't you?","TWN":"看來你一直在這裡等到太陽下山。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"해가 지면 마을 안을 용의주도하게 움직이기 편해질 테니까.","JPN":"日が暮れたら、村の中でこっそり行動しやすくなるから。","ENG":"It'd be easier to sneak around the village after dark.","TWN":"太陽下山後，在村子裡行動會更加方便。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"그런 나쁜 생각은 안 했어요.","JPN":"そんな悪いこと、考えてないもん。","ENG":"I didn't mean anything bad.","TWN":"我沒有想過那樣的壞主意。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"그냥… 마을로 돌아가는 게 무서웠을 뿐이에요.","JPN":"ただ……村に戻るのが怖かったの。","ENG":"I was just... scared to go back to the village.","TWN":"只是……我只是害怕回到村子裡而已。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그래. 적어도 잘못에 대한 자각은 있군.","JPN":"そうか。せめて悪いことをしたという自覚はあるのだな。","ENG":"I see. At least you understand what you did was wrong.","TWN":"是啊，至少你意識到自己的錯誤了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"빨리 돌아가서 사과하게. 무슨 연유인지는 몰라도 도둑질은 나쁜 거야.","JPN":"早く村に行って謝りなさい。どういう理由かは知らないが、泥棒は悪いことだ。","ENG":"You should go back and apologize. Whatever your reasons, stealing is wrong.","TWN":"快回去道歉吧。不管是什麼原因，偷東西都是不對的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"나쁜 건 당신들이잖아요.","JPN":"悪いのはあなたたちの方じゃない。","ENG":"You're the bad ones.","TWN":"壞的是你們吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"뭐?","JPN":"何だと？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"나쁜 건 당신들이라 했어요. 우리가 얼마나 힘든 상황인지 신경도 안 썼잖아요.","JPN":"悪いのはあなたたちの方だって言ったの。私たちの辛さなんて気にもとめない。","ENG":"I said you're the bad ones. You didn't care how desperate we were.","TWN":"壞的是你們。你們根本不關心我們有多麼艱難。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"그냥 마을에서 며칠 머무르겠다고 했는데. 땅바닥에서 자도 상관없다고 했는데.","JPN":"ただ、村には数日泊まるだけって言ったのに。野宿でもいいって言ったのに。","ENG":"All we wanted was to stay in the village a few days. We said we didn't even mind sleeping on the ground.","TWN":"只是說會在村子裡待幾天。說睡在地上也沒關係。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"냄새 난다고, 불편하다고 돌을 던졌어요. 심한 욕을 일삼았어요. 그래서 훔친 거예요.","JPN":"臭いって、嫌だって石を投げた。ひどいこと言った。だから盗んだの。","ENG":"But you said we smelled. You threw rocks at us. You cursed at us. That's why we stole.","TWN":"說有味道，說不舒服，就扔石頭。還罵得很難聽。所以才偷東西。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"옥수수 세 개를 말인가?","JPN":"トウモロコシ3つをか？","ENG":"Three ears of corn?","TWN":"玉米三個嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"둘은 오빠랑 제가 먹을 거고, 하나는… 깽값이에요. 돌 맞은 데가 아직도 부었어요.","JPN":"2つは私たちが食べる分で、1つは……ばいしょう金。石が当たったところがまだ腫れてるの。","ENG":"Two were for my brother and me. The third... was for compensation. My bruise still hasn't gone down.","TWN":"兩個是我和哥哥要吃的，另一個是……賠償金。被石頭砸到的地方還腫著呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"마을 사람에게 오빠가 사과하러 왔다고 들었네.","JPN":"君の兄が謝りに来たと村の人から聞いた。","ENG":"I heard your brother came to apologize.","TWN":"聽村裡的人說哥哥來道歉了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"알아요.","JPN":"知ってる。","ENG":"I know.","TWN":"我知道。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그렇다면 자네는 왜 여기 남아있는 거지?","JPN":"なら、君はなぜここにいる？","ENG":"Then why didn't you go with him?","TWN":"那麼你為什麼還留在這裡呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"제가 사과하면 오빠가 잘못했다는 걸 인정하는 거잖아요.","JPN":"私が謝ったら、お兄ちゃんが悪いことをしたって認めることになるもん。","ENG":"If I apologize, it means he did something wrong.","TWN":"如果我道歉，那不就意味著哥哥承認自己錯了嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"오빠는 잘못 없어요. 제가 짐덩어리라 매번 고생만 하는 걸요.","JPN":"お兄ちゃんは悪くない。私がお荷物だからいつも苦労してる。","ENG":"But he didn't. He always suffers because I'm a burden.","TWN":"哥哥沒有錯。都是我這個累贅讓你每次都辛苦。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"확실히 자네에게 큰 잘못은 없을지도 모르지.","JPN":"確かに、君はそんなに悪いことをしていないのかもしれない。","ENG":"Maybe you didn't do anything seriously wrong.","TWN":"確實可能不是你的大錯。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"하지만 고개를 숙인다는 건 부끄러운 일이 아니야.","JPN":"しかし、人に頭を下げることは恥ずかしいことではない。","ENG":"But lowering your head isn't shameful.","TWN":"但是低頭並不是一件羞恥的事情。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"자신의 부족함을 받아들일 수 있는 건 물론, 타인을 배려하는 마음을 지녔다는 뜻이지.","JPN":"自分の至らなさを受け入れることができる上に、他人を思いやる心を持っているという証拠だ。","ENG":"It means you can accept your flaws, and it shows you care about others.","TWN":"不僅能夠接受自己的不足，還意味著擁有體貼他人的心。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"그러면 뭐가 달라지는데요?","JPN":"それで何が変わるの？","ENG":"So what changes if I do?","TWN":"那會有什麼不同呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"자네가 고개를 숙여준다면 옥수수 세 개보다 배부른 식사를 제공하지.","JPN":"君が頭を下げるなら、トウモロコシ3つよりもお腹を満たせる食事を提供しよう。","ENG":"If you apologize, I'll make sure you get a meal better than three ears of corn.","TWN":"如果你願意低頭，我會提供比三根玉米更豐盛的餐食。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"어떤가?","JPN":"どうだ？","ENG":"How's that?","TWN":"怎麼樣？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"……그럼 할게요, 사과.","JPN":"……じゃあやる。謝る。","ENG":"...Fine. I'll apologize.","TWN":"……那我就做吧，道歉。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"좋은 판단이야.","JPN":"いい判断だ。","ENG":"Wise choice.","TWN":"明智的判斷。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그럼, 내 뒤를 따라오게.","JPN":"では、私についてきなさい。","ENG":"Then come with me.","TWN":"那就跟著我來吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"다, 다시 생각해보니 이건 좀…….","JPN":"か、考え直した方がいいかも……","ENG":"N-now that I think about it, maybe not...","TWN":"但、但是再仔細想想，這個有點兒……"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"쉽게 내뱉지 못할 말은 시간이 흐를수록 무겁게 느껴지겠지.","JPN":"簡単に口に出せない言葉は、時が経てば経つほど重く感じるだろう。","ENG":"The longer you delay hard words, the heavier they become.","TWN":"那些難以輕易說出口的話，隨著時間的流逝會變得越來越沉重吧。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"고작 옥수수 세 개로 문제를 키울 생각이라면 말릴 생각은 없네.","JPN":"たったトウモロコシ3つで事を大きくするつもりなら、止めるつもりはない。","ENG":"If you want to blow this up over three ears of corn, I won't stop you.","TWN":"如果你打算用區區三根玉米來製造麻煩，我是不會阻止你的。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"으윽…….","JPN":"うっ……","ENG":"Ngh...","TWN":"呃……"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"……죄송합니다. 제가 잘못했어요.","JPN":"……すみません。私が悪かったです。","ENG":"...I'm sorry. I was wrong.","TWN":"……非常抱歉。是我做錯了。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"으음. 어린 친구가 그렇다고 하니, 다들 그만 용서해 주심이 어떠십니까?","JPN":"うむ。幼い子どもがこうして謝罪しているんだ、みんな許してあげたらどうですか？","ENG":"Hmm. Since the child admits it, perhaps we should let it go?","TWN":"嗯。既然小朋友都這麼說了，大家就原諒他她吧？"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WOMEN_PRIDE_NULL_NULL","text":{"KOREA":"잠시만요, 촌장님. 이건 사과만으로 해결될 문제가 아니에요.","JPN":"待ってください、村長。これは謝罪だけで解決する問題ではありません。","ENG":"Just a moment, Chief. This isn't something an apology can fix.","TWN":"請稍等，村長。這不是一個僅憑道歉就能解決的問題。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WOMEN_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L38_1","type":"dialog","speaker":"WOMEN_PRIDE_NULL_NULL","text":{"KOREA":"몇 년 전부터 침식 지대의 반경이 넓어지고 있어요. 덕분에 식량문제나 주거 환경도 불편해지고 있고요.","JPN":"数年前から侵食地帯がどんどん広がっています。おかげで食糧問題や住居の問題も深刻化しているんです。","ENG":"The Corrupted Area has been expanding for years. We're short on food and housing as it is.","TWN":"從幾年前開始，侵蝕地帶的範圍不斷擴大。由於這個原因，糧食問題和居住環境也變得不便了。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WOMEN_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"WOMEN_PRIDE_NULL_NULL","text":{"KOREA":"버밍엄 교수님의 도움으로 마을은 안전하지만, 외부인을 받아들이기에는 위험부담이 커요.","JPN":"バーミンガム教授のおかげで村は安全ですが、部外者を受け入れるのはリスクが大きすぎます。","ENG":"Thanks to Professor Birmingham, the village is safe, but we can't take chances on outsiders.","TWN":"在伯明罕教授的幫助下，村莊是安全的，但接納外來人風險很大。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WOMEN_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MEN_PRIDE_NULL_NULL","text":{"KOREA":"저도 동감입니다. 사연은 딱하나 마을의 규칙에 예외를 둘 순 없어요.","JPN":"同意見です。可哀想なのは確かだけど、ルールに例外を置くわけにはいきません。","ENG":"I agree. It's unfortunate, but we can't make exceptions to village rules.","TWN":"我也同意。雖然情況特殊，但不能對村子的規矩破例。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEN_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMEN_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MEN_PRIDE_NULL_NULL","text":{"KOREA":"하다못해 저 아이들의 신원을 증명할 보호자도 없잖습니까?","JPN":"それに、あの子たちの身元を証明してくれる保護者もいないじゃないですか。","ENG":"They don't even have a guardian who can vouch for them.","TWN":"甚至連證明那些孩子身份的監護人都沒有吧？"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEN_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMEN_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MEN_PRIDE_NULL_NULL","text":{"KOREA":"최근 인간의 탈을 쓴 침식체가 목격됐다는 소문도 있으니, 동정심을 앞세워 판단을 그르쳐선 안 됩니다.","JPN":"最近人間の見た目をした侵食体が見つかったという噂もあるし、同情で判断を謝ってはいけません。","ENG":"There are rumors of C.O.s in human form. We can't let sympathy cloud our judgment.","TWN":"最近有傳聞稱目擊到披著人類外衣的侵蝕體，所以不能因為同情心而判斷失誤。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEN_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMEN_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"치, 침식체 아니에요.","JPN":"し、侵食体じゃない。","ENG":"W-we're not C.O.s.","TWN":"我、我們不是侵蝕體。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"저랑 오빠는 침식체 아니라구요…….","JPN":"私とお兄ちゃんは、侵食体じゃないもん……","ENG":"My brother and I aren't C.O.s...","TWN":"我和哥哥不是侵蝕體……"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"잠시 괜찮으십니까, 촌장님.","JPN":"少しいいでしょうか、村長。","ENG":"May I speak, Chief?","TWN":"等一下，村長。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"버밍엄 교수님? 무슨 일이십니까?","JPN":"バーミンガム教授？　どうされました？","ENG":"Yes, Professor Birmingham?","TWN":"伯明罕教授？有什麼事嗎？"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"다른 분들만 괜찮으시다면 이 아이는 제가 맡겠습니다.","JPN":"皆さんさえ良ければ、この子は私が預かります。","ENG":"If no one objects, I'll take responsibility for this child.","TWN":"如果其他人都沒問題的話，這個孩子就由我來負責吧。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"이 아이를 교수님이요?","JPN":"この子を教授が？","ENG":"You, Professor?","TWN":"這個孩子是教授的嗎？"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"예. 무슨 일이 있다면 책임은 제가 지겠습니다.","JPN":"はい。何かあった場合、責任は私が取ります。","ENG":"Yes. I'll take full responsibility if anything happens.","TWN":"好的。如果發生什麼事情，我會負責的。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"무슨 일이 생기지 않도록 미연에 방지할 거고요.","JPN":"もちろん何かがないように、未然に防ぎますし。","ENG":"But I'll also make sure nothing does.","TWN":"我會預防任何事情的發生。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"흐음… 여러분은 어떻게 생각하십니까?","JPN":"ふむ……皆さんの意見はどうですか？","ENG":"Hmm... What does everyone else think?","TWN":"嗯…各位怎麼看呢？"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"버밍엄 교수님이 저리 말씀하시는 걸 보면 위험한 애들은 아닌 건가?","JPN":"バーミンガム教授があそこまで言うなら、危険な子たちじゃないのかな？","ENG":"If the professor says so, maybe they're not so dangerous?","TWN":"伯明罕教授這麼說的話，看來他們不是危險人物嗎？"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"그런 것 같은데? 교수님이 아무 생각 없이 저러실 리는 없잖아.","JPN":"そうみたいだよ？　教授がなんの理由もなくあんなことを言うはずがないし。","ENG":"Yeah. He wouldn't say this lightly.","TWN":"好像是這樣吧？教授不可能無緣無故那樣做的。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WOMEN_PRIDE_NULL_NULL","text":{"KOREA":"하, 하지만 아무리 교수님이라도 저 아이들의 신원을 증명할 순 없잖아요?","JPN":"で、でもいくら教授でもあの子たちの身元は証明できないじゃないですか。","ENG":"S-still, even the professor can't prove who these kids are.","TWN":"下，但即使是教授也無法證明那些孩子的身份吧？"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMEN_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L12_1","type":"dialog","speaker":"WOMEN_PRIDE_NULL_NULL","text":{"KOREA":"저 아이들이 지금껏 무슨 일을 해왔는지 어떻게 알고…….","JPN":"今まで何をして生きてきたのかもわかりませんし……","ENG":"We don't know what they've been through...","TWN":"那些孩子們究竟做過什麼事情，該怎麼知道……"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMEN_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"오빠 쪽은 자신의 잘못을 시인했고, 동생은 그런 오빠를 위해 제 발로 마을에 돌아왔습니다.","JPN":"兄の方は自分の過ちを認め、妹はそんな兄のために自ら村に帰ってきました。","ENG":"The boy admitted his wrongdoing, and the girl came back for his sake.","TWN":"哥哥承認了自己的錯誤，妹妹為了這樣的哥哥自願回到了村子裡。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"현실에 몰렸을 뿐 심성은 올바르다는 뜻이죠. 부인께서 걱정하실 일은 없을 겁니다.","JPN":"追い込まれているだけで、心はまっすぐな子たちです。夫人が心配するようなことはないでしょう。","ENG":"They're just cornered by life. But their hearts are in the right place. You have nothing to fear.","TWN":"只是被現實逼迫，心性還是正直的。夫人不必擔心。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WOMEN_PRIDE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMEN_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WOMEN_PRIDE_NULL_NULL","text":{"KOREA":"예. 교수님이 그러시다면 저도 불만 없어요.","JPN":"はい、教授がそこまでおっしゃるなら、私も文句はありません。","ENG":"All right. If the Professor's vouching, I won't object.","TWN":"是的。如果教授你這麼說的話，我也沒有意見。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMEN_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"결정됐군요. 그럼-.","JPN":"決まりましたね。では……","ENG":"Then it's settled. Now–","TWN":"那就定下來了。那就-"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"아뇨. 아직입니다, 촌장님.","JPN":"いえ、まだです、村長。","ENG":"No. Not yet, Chief.","TWN":"不，還沒結束，村長。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"아직 이 아이의 의견은 묻지 않았잖습니까.","JPN":"まだこの子の意見を聞いていないじゃないですか。","ENG":"We haven't heard the child's own answer.","TWN":"我們還沒有詢問這個孩子的意見呢。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"네? 저, 저요?","JPN":"え？　わ、私？","ENG":"Huh? M-me?","TWN":"嗯？我，我嗎？"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"당장은 자네에게 내민 이 손길이 희망처럼 느껴질 걸세.","JPN":"今は差し伸べられた手が希望のように感じるだろう。","ENG":"Right now, this hand I'm offering may feel like hope.","TWN":"此刻，我伸出的這只手會讓你感受到希望。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"허나 단언하지. 나와 함께 가면 자네는 먼 미래에 괴로운 경험을 하게 될 거야.","JPN":"しかし断言しよう。私と共に行けば、君は遠い未来、辛い経験をすることになる。","ENG":"But let me be clear. If you come with me, you'll face pain in the future.","TWN":"不過我可以斷言。和我一起走的話，你將來會有痛苦的經歷。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그럼에도 내 손을 잡겠는가?","JPN":"それでも私の手を取るかね。","ENG":"Even so, will you take it?","TWN":"即便如此，你還要抓住我的手嗎？"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"사, 상관없어요. 안 좋은 일은 이미 수도 없이 겪었는 걸요.","JPN":"か、関係ない。辛いことはもうたくさん経験したから。","ENG":"I-it's fine. I've already been through plenty of bad things.","TWN":"沒關係，我已經經歷過無數次不好的事情了。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"그러니까… 아저씨를 믿을게요.","JPN":"だから……おじさんのこと、信じる。","ENG":"So... I'll trust you.","TWN":"所以……我會相信叔叔的。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그런가.","JPN":"そうか。","ENG":"I see.","TWN":"是嗎。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"자네가 그렇다면, 나와 함께 가지.","JPN":"君の気持ちがそうなら、一緒に行こう。","ENG":"Then come with me.","TWN":"如果你這麼說，那我就和你一起去吧。"},"stage":{"bg":"RESTAURANT_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"저기, 아저씨.","JPN":"あの、おじさん。","ENG":"Um, mister.","TWN":"喂，叔叔。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"아저씨는 좋은 사람인가요?","JPN":"おじさんはいい人？","ENG":"Are you a good person?","TWN":"叔叔是好人嗎？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"선악을 따진다면 악인에 가깝겠지.","JPN":"善悪を問われたら、悪人に近いだろう。","ENG":"If we're judging good and evil, I'm probably closer to evil.","TWN":"如果要分辨善惡的話，我更接近惡人吧。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"그럼 왜 저를 도와주는 거예요?","JPN":"じゃあなんで私を助けるの？","ENG":"Then why are you helping me?","TWN":"那你為什麼要幫我呢？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"혹시 노예로 팔아 넘기실 생각이라면 죄송해요.","JPN":"奴隷として売り渡すつもりなら、ごめんなさい。","ENG":"If you're planning to sell me as a slave, I'm sorry.","TWN":"如果你打算把我賣作奴隸的話，那我很抱歉。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"전 글도 못 읽고 머리도 나쁜 걸요.","JPN":"私は字も読めないし、頭も悪いから。","ENG":"I can't read, and I'm not smart.","TWN":"我既不識字，腦子也不好使。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그건 걱정 말게. 자네들은 기사단에서 교육을 받게 될 거야.","JPN":"それは心配するな。君たちは騎士団で教育を受けることになる。","ENG":"Don't worry about that. You'll be educated by the Order.","TWN":"那就不用擔心了。你們會在騎士團接受訓練的。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"기사단이요?","JPN":"騎士団？","ENG":"The Order?","TWN":"騎士團嗎？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"내가 오랜 기간 협력하고 있는 기관일세. 그곳에서라면 자네도…….","JPN":"私が長い間協力している機関だ。そこでなら、君も……","ENG":"An institution I've worked with for a long time. There, you'll...","TWN":"這是我長期合作的機構。在那裡，你也可以……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"에스텔!","JPN":"エステル！","ENG":"Esther!!","TWN":"艾斯特！"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"오빠!!","JPN":"お兄ちゃん！！","ENG":"Brother!!","TWN":"哥哥！！"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"정말 감사합니다. 촌장님께 이야기를 들었어요.","JPN":"本当にありがとうございます。村長から話を聞きました。","ENG":"Thank you so much. Chief told me everything.","TWN":"真的非常感謝。我聽村長說了。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"이 은혜를 어떻게 갚아야 할지…….","JPN":"この恩をどうお返しすればいいか……","ENG":"I don't know how to repay this kindness...","TWN":"真不知道該怎麼報答你們……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"있지, 오빠. 아저씨가 우릴 기사단에 보낼 거래.","JPN":"ねえ、お兄ちゃん。おじさんが私たちを騎士団に送るって言ってたよ。","ENG":"Hey. The man said we can join the Order!","TWN":"你知道嗎，哥哥。叔叔說要把我們送到騎士團去。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"거기서 글도 배울 수 있댔어!","JPN":"そこで文字も教えてもらえるんだって！","ENG":"He said we'll get to learn to read too!","TWN":"在那裡也可以學習識字！"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"기사단? 거긴 가문에 속한 사람들만 들어갈 수 있는 곳 아니야?","JPN":"騎士団？　そこは家門に所属する人しか入れないとこじゃない？","ENG":"The Order? Isn't that only for people with family names?","TWN":"騎士團？那裡不是只有家族成員才能加入嗎？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"우린 성도 없는 평민인데…….","JPN":"僕たちは家名もない平民なのに……","ENG":"We're just nameless commoners...","TWN":"我們只是沒有姓氏的平民……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……그래.","JPN":"……ああ。","ENG":"...Indeed.","TWN":"……是啊。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"이 또한… 운명인가.","JPN":"これもまた、運命か。","ENG":"But perhaps this too... is fate.","TWN":"這也是……命運嗎。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"가문에 대한 걱정은 말게. 내 후견 아래, 자네들은 새로운 성을 갖게 될 거야.","JPN":"家門のことなら心配するな。私が後見人になり、君たちは新しい家名を持つことになるだろう。","ENG":"Don't worry about that. Under my sponsorship, you'll be granted a new family name.","TWN":"不用擔心家族的事。在我的守護下，你們將擁有新的城堡。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_CHILD_NULL_NULL","text":{"KOREA":"저희가 아저씨 성을 따라가는 건가요?","JPN":"私たち、おじさんの家名になるの？","ENG":"We'll take your name?","TWN":"我們是要跟著叔叔的姓氏走嗎？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"난 버밍엄 가문의 정식 후계자가 아니니 그건 힘들겠군.","JPN":"私はバーミンガム家の正式な後継者ではないから、それは難しいな。","ENG":"I'm not the rightful heir to House Birmingham, so that's not possible.","TWN":"我不是伯明罕家族的正式繼承人，所以那很難。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"말 그대로 새로운 가문을 창설하는 걸세. 자네 둘이 속한 가족이라는 증표지.","JPN":"文字通り、新しい家門をつくるのだよ。君たち2人が所属している家族という証だ。","ENG":"This will be a new house. A symbol that you two belong to the same family.","TWN":"字面意思就是創建一個新的家族。這是你們兩個所屬的家庭象徵。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_CHILD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"가문의 이름은… 그래.","JPN":"家門の名は……そうだな。","ENG":"Its name... yes.","TWN":"家族的名字是……是啊。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"명예로운 기사를 뜻하는 <color=#ffd34c>슈발리에</color>가 좋겠군.","JPN":"誇り高き騎士を意味する<color=#ffd34c>シュヴァリエ</color>がいいな。","ENG":"Let it be <color=#ffd34c>Chevalier</color>. A name that means honorable knight.","TWN":"我覺得<color=#ffd34c>聖騎士</color>這個名字不錯，象徵著榮譽。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"알렌 경의 죽음으로 다시 올 일은 없을 거라 생각했는데.","JPN":"アレン卿が亡くなって、二度とここに来ることはないと思っていたが。","ENG":"I thought I'd never come back after Sir Allen's death.","TWN":"我以為艾倫卿死後就不會再來了。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"결국…… 여기까지 와버렸나.","JPN":"結局……ここまで来てしまったか。","ENG":"But... I ended up here again.","TWN":"最終……還是走到了這一步。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"오랜만이에요.","JPN":"お久しぶりです。","ENG":"It's been a while.","TWN":"好久不見啊。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"다녀왔습니다, 여러분.","JPN":"ただいま帰りました、皆さん。","ENG":"I'm home, everyone.","TWN":"我回來了，各位！"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};